import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Aggiornare Fabric","description":"Una guida passo per passo su come aggiornare Fabric.","frontmatter":{"title":"Aggiornare Fabric","description":"Una guida passo per passo su come aggiornare Fabric.","authors":["IMB11","modmuss50"],"search":false,"files":[]},"headers":[],"relativePath":"it_it/1.20.4/players/updating-fabric.md","filePath":"versions/1.20.4/translated/it_it/players/updating-fabric.md","lastUpdated":1739538073000}`);var c={name:`it_it/1.20.4/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Aggiornare Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Aggiornare Fabric”">​</a></h1><p>Questa guida ti aiuterà nell&#39;aggiornare Fabric per quanto riguarda il Launcher di Minecraft.</p><p>Per launcher di terze parti, dovresti consultare la loro documentazione.</p><p>Aggiornare Fabric è un processo molto simile all&#39;installazione di Fabric, per cui alcune parti di questa guida saranno uguali a quelle della guida <a href="./installing-fabric">Installare Fabric</a>.</p><h2 id="perche-dovrei-aggiornare-il-loader-di-fabric" tabindex="-1">Perché Dovrei Aggiornare il Loader di Fabric? <a class="header-anchor" href="#perche-dovrei-aggiornare-il-loader-di-fabric" aria-label="Permalink to “Perché Dovrei Aggiornare il Loader di Fabric?”">​</a></h2><p>Mod più recenti potrebbero richiedere una versione più moderna del Loader di Fabric per funzionare, quindi è importante tenerlo aggiornato per assicurarti di poter usare le mod più recenti.</p><p>Per launcher di terze parti, dovresti consultare la loro documentazione.</p><h2 id="_1-scarica-l-installer-di-fabric" tabindex="-1">1. Scarica l&#39;installer di Fabric <a class="header-anchor" href="#_1-scarica-l-installer-di-fabric" aria-label="Permalink to “1. Scarica l&#39;installer di Fabric”">​</a></h2><p>Puoi scaricare l&#39;installer di Fabric dal <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Sito di Fabric</a>.</p><p>Se usi Windows, scarica la versione <code>.exe</code> (<code>Scarica per Windows</code>), perché non necessita di Java per essere installata sul tuo sistema. Essa usa invece la versione di Java inclusa nel launcher ufficiale.</p><p>Per macOS e Linux, dovresti scaricare la versione <code>.jar</code>. A volte, dovrai installare Java prima di questo passaggio.</p><h2 id="_2-esegui-l-installer-di-fabric" tabindex="-1">2. Esegui l&#39;Installer di Fabric <a class="header-anchor" href="#_2-esegui-l-installer-di-fabric" aria-label="Permalink to “2. Esegui l&#39;Installer di Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Chiudi Minecraft e il Launcher di Minecraft prima d&#39;iniziare l&#39;installazione.</p></div><details class="details custom-block"><summary>Informazioni per utenti macOS</summary><p>Su macOS, potresti dover fare click destro sul file <code>.jar</code> nella tua cartella download e cliccare <code>Apri</code> per avviarlo.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu contestuale macOS sull&#39;Installer di Fabric" loading="lazy"></p><p>Quando ti viene chiesto &quot;Sei sicuro di volerlo aprire?&quot;, clicca di nuovo <code>Apri</code>.</p></details><p>Una volta aperto l&#39;installer, dovresti vedere una schermata come questa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer con &quot;Installa&quot; evidenziato" loading="lazy"></p><p>Per installare Fabric, semplicemente scegli la versione di gioco dal menu a tendina, e clicca <code>Installa</code>.</p><p>Per aggiornare Fabric, assicurati semplicemente che la versione del gioco e quella del Loader siano corrette poi clicca <code>Installa</code>.</p><p><strong>Assicurati di deselezionare &#39;Crea Profilo&#39; quando esegui l&#39;installer, altrimenti creerà un nuovo profilo, che in questo caso non ci serve.</strong></p><h2 id="_3-apri-il-profilo-nel-launcher-di-minecraft" tabindex="-1">3. Apri il Profilo nel Launcher di Minecraft <a class="header-anchor" href="#_3-apri-il-profilo-nel-launcher-di-minecraft" aria-label="Permalink to “3. Apri il Profilo nel Launcher di Minecraft”">​</a></h2><p>Appena l&#39;installer ha finito, puoi aprire il Launcher di Minecraft e recarti nella scheda <code>Installazioni</code>. Dovresti andare al tuo profilo Fabric e aprire la schermata modifica.</p><p>Sostituisci la versione con la nuova versione del Loader di Fabric che hai appena installato, e premi <code>Salva</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Aggiornare la versione del Loader di Fabric nel Launcher di Minecraft" loading="lazy"></p><h2 id="_4-hai-finito" tabindex="-1">4. Hai Finito! <a class="header-anchor" href="#_4-hai-finito" aria-label="Permalink to “4. Hai Finito!”">​</a></h2><p>Appena avrai completato i passaggi potrai tornare alla scheda <code>Gioca</code>, selezionare il profilo Fabric dal menu a tendina nell&#39;angolo in basso a sinistra e premere gioca!</p><p>Se incontri qualsiasi problema nel seguire questa guida, puoi chiedere aiuto nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};